import Layout from "../components/Layout";

const AboutMe = () => {
  return (
    <>
      <Layout>About me</Layout>
    </>
  );
};

AboutMe.getInitialProps = async ctx => {
  const res = await require('../markdown/aboutme.md')
  return { res }
}

export default AboutMe;
